303→        response_format: 'stream',
304→        ai_analysis_config: {
305→            system_prompt: system_prompt || '',
306→            target_field: 'query',
307→            history: history || [],
308→        },
309→    }
310→
311→    return fetch(url, {
312→        method: 'POST',
313→        headers,
314→        credentials: 'include',
315→        signal,
316→        body: JSON.stringify(handlerParams(payload)),
317→    })
318→}
