 18→    /**
 19→     * 计算 ISO 周边界（周一~周日）.
 20→     *
 21→     * @return array{week_start: string, week_end: string}
 22→     */
 23→    public function getWeekBounds(string $date): array
 24→    {
 25→        $carbon = Carbon::parse($date);
 26→        $weekStart = $carbon->copy()->startOfWeek(Carbon::MONDAY)->toDateString();
 27→        $weekEnd = $carbon->copy()->endOfWeek(Carbon::SUNDAY)->toDateString();
 28→
 29→        return ['week_start' => $weekStart, 'week_end' => $weekEnd];
 30→    }
 31→
 32→    /**
 33→     * 从该用户本周已提交的日报中，取 reporter_ids 和 cc_ids 的并集.
 34→     *
 35→     * @return array{0: string, 1: string} [reporter_ids, cc_ids]
 36→     */
 37→    public function resolveReporterAndCcIds(int $sfuserId, string $weekStart, string $weekEnd): array
 38→    {
 39→        $reports = DailyReport::where('sfuser_id', $sfuserId)
 40→            ->where('report_date', '>=', $weekStart)
 41→            ->where('report_date', '<=', $weekEnd)
 42→            ->where('status', DailyReport::STATUS_COMMITTED)
 43→            ->select(['reporter_ids', 'cc_ids'])
 44→            ->get();
 45→
 46→        $reporterIds = [];
 47→        $ccIds = [];
 48→        foreach ($reports as $report) {
 49→            foreach (array_filter(explode(',', $report->reporter_ids)) as $id) {
 50→                $reporterIds[(int)$id] = true;
 51→            }
 52→            foreach (array_filter(explode(',', $report->cc_ids)) as $id) {
 53→                $ccIds[(int)$id] = true;
 54→            }
 55→        }
 56→
 57→        return [
 58→            implode(',', array_keys($reporterIds)),
 59→            implode(',', array_keys($ccIds)),
 60→        ];
 61→    }
