 63→    /**
 64→     * 查找或创建 Room，优先精确匹配 project_name，再模糊匹配 aliases.
 65→     */
 66→    public function findOrCreateRoom(string $projectName): int
 67→    {
 68→        $projectName = trim($projectName);
 69→        if (empty($projectName)) {
 70→            return 0;
 71→        }
 72→
 73→        // 精确匹配 project_name
 74→        $room = DailyReportAiRoom::where('project_name', $projectName)
 75→            ->where('status', DailyReportAiRoom::STATUS_ACTIVE)
 76→            ->first();
 77→        if ($room) {
 78→            return $room->id;
 79→        }
 80→
 81→        // 模糊匹配 aliases（用 MySQL JSON_CONTAINS 代替全表扫描）
 82→        $aliasRoom = DailyReportAiRoom::where('status', DailyReportAiRoom::STATUS_ACTIVE)
 83→            ->whereRaw('JSON_CONTAINS(aliases, ?)', [json_encode($projectName)])
 84→            ->first();
 85→        if ($aliasRoom) {
 86→            return $aliasRoom->id;
 87→        }
 88→
 89→        // 未找到，用 firstOrCreate 防止并发重复（配合 unique 约束）
 90→        try {
 91→            $newRoom = DailyReportAiRoom::firstOrCreate(
 92→                ['project_name' => $projectName],
 93→                ['aliases' => [], 'status' => DailyReportAiRoom::STATUS_ACTIVE],
 94→            );
 95→
 96→            if ($newRoom->wasRecentlyCreated) {
 97→                Log::info('[lbl][0423-周摘要][Room] 新建项目', [
 98→                    'room_id' => $newRoom->id,
 99→                    'project_name' => $projectName,
100→                ]);
101→            }
102→
103→            return $newRoom->id;
104→        } catch (\Throwable $e) {
105→            // 唯一键冲突兜底：再查一次
106→            Log::warning('[lbl][0423-周摘要][Room] 创建冲突，重新查询', [
107→                'project_name' => $projectName,
108→                'error' => $e->getMessage(),
109→            ]);
110→            $existing = DailyReportAiRoom::where('project_name', $projectName)->first();
111→
112→            return $existing ? $existing->id : 0;
113→        }
114→    }
