119→    public function saveTunnel(int $roomId, int $sfuserId, string $weekStart): void
120→    {
121→        if ($roomId <= 0) {
122→            return;
123→        }
124→
125→        DailyReportAiTunnel::insertOrIgnore([
126→            'room_id' => $roomId,
127→            'sfuser_id' => $sfuserId,
128→            'week_start' => $weekStart,
129→            'created_at' => now(),
130→        ]);
